def largest_smallest_integers(lst):
    negative_integers = [x for x in lst if x < 0]
    positive_integers = [x for x in lst if x > 0]

    largest_negative = max(negative_integers) if negative_integers else None
    smallest_positive = min(positive_integers) if positive_integers else None

    return (largest_negative, smallest_positive)

def compare_one(a, b):
    """
    Create a function that takes integers, floats, or strings representing
    real numbers, and returns the larger variable in its given variable type.
    Return None if the values are equal.
    Note: If a real number is represented as a string, the floating point might be . or ,
    """

    def _normalize_value(val):
        """
        Helper function to normalize input values to a comparable float.
        Handles string representations with ',' or '.' as decimal separators.
        """
        if isinstance(val, (int, float)):
            return float(val)
        elif isinstance(val, str):
            # Replace comma with dot for consistent float conversion
            return float(val.replace(',', '.'))
        else:
            raise TypeError("Unsupported type for comparison")

    try:
        norm_a = _normalize_value(a)
        norm_b = _normalize_value(b)
    except (ValueError, TypeError):
        # This catch handles cases where string conversion to float fails
        # or unsupported types are passed.
        # The problem description implies valid real number representations,
        # so this might be an edge case not explicitly tested but good to have.
        return None

    if norm_a == norm_b:
        return None
    elif norm_a > norm_b:
        return a
    else:
        return b

def sum_squares(lst):
    """"
    This function will take a list of integers. For all entries in the list, the function shall square the integer entry if its index is a 
    multiple of 3 and will cube the integer entry if its index is a multiple of 4 and not a multiple of 3. The function will not 
    change the entries in the list whose indexes are not a multiple of 3 or 4. The function shall then return the sum of all entries. 

    Examples:
    For lst = [1,2,3] the output should be 6
    For lst = []  the output should be 0
    For lst = [-1,-5,2,-1,-5]  the output should be -126
    """
    if not lst:
        return 0

    modified_list = list(lst)  # Create a mutable copy of the list

    for i in range(len(modified_list)):
        if i % 3 == 0:
            modified_list[i] = modified_list[i] ** 2
        elif i % 4 == 0:
            modified_list[i] = modified_list[i] ** 3

    return sum(modified_list)

def x_or_y(n, x, y):
    """A simple program which should return the value of x if n is 
    a prime number and should return the value of y otherwise.

    Examples:
    for x_or_y(7, 34, 12) == 34
    for x_or_y(15, 8, 5) == 5

    """
    if n < 2:
        return y  # Numbers less than 2 are not prime

    for i in range(2, int(n**0.5) + 1):
        if n % i == 0:
            return y  # n is divisible by i, so it's not prime

    return x  # If no divisors found, n is prime

def even_odd_count(num):
    """Given an integer. return a tuple that has the number of even and odd digits respectively.

     Example:
        even_odd_count(-12) ==> (1, 1)
        even_odd_count(123) ==> (1, 2)
    """
    even_count = 0
    odd_count = 0

    # Convert the number to its absolute value string to iterate through digits
    for digit_char in str(abs(num)):
        digit = int(digit_char)
        if digit % 2 == 0:
            even_count += 1
        else:
            odd_count += 1

    return (even_count, odd_count)

def solve(s):
    """You are given a string s.
    if s[i] is a letter, reverse its case from lower to upper or vise versa,
    otherwise keep it as it is.
    If the string contains no letters, reverse the string.
    The function should return the resulted string.
    Examples
    solve("1234") = "4321"
    solve("ab") = "AB"
    solve("#a@C") = "#A@c"
    """
    has_letters = any(char.isalpha() for char in s)

    if not has_letters:
        return s[::-1]
    else:
        result_chars = []
        for char in s:
            if char.isalpha():
                if char.islower():
                    result_chars.append(char.upper())
                else:
                    result_chars.append(char.lower())
            else:
                result_chars.append(char)
        return "".join(result_chars)
